export const generateMockItems = (categoryId, isEbook = false) => {
  return Array.from({ length: 20 }, (_, i) => ({
    id: `${categoryId}-item-${i + 1}`,
    title: `${isEbook ? 'Read' : 'Watch'}: ${categories.find(c => c.id === categoryId)?.name} ${isEbook ? 'Story' : 'Episode'} ${i + 1}`,
    description: `Enjoy the best ${categoryId} content for the whole family to explore.`,
    duration: isEbook ? `${Math.floor(Math.random() * 50 + 10)} mins read` : `${Math.floor(Math.random() * 15 + 5)}:${Math.floor(Math.random() * 50 + 10)}`,
    thumbnail: `https://images.unsplash.com/photo-1574375927938-d5a98e8ffe85?auto=format&fit=crop&w=400&q=80`,
    categoryId,
  }));
};




